// ── Input normalisation ──────────────────────────────────────────
// Accepts either a single invoice object or an array
// Normalises field names for downstream LLM prompt

const body = $input.first().json.body || $input.first().json;
const invoices = Array.isArray(body) ? body : [body];

const normalised = invoices.map((inv, idx) => {
  return {
    index: idx,
    invoice_id:    inv.invoice_id    || inv.PO            || `INV-${idx+1}`,
    serial_number: inv.serial_number || inv['Serial Number'] || 'UNKNOWN',
    safe_age_yr:   inv.safe_age_yr   || inv['Safe manufacture year'] || null,
    labour_charge: inv.labour_charge || inv.Lineitem_1_UnitPrice || 0,
    parts_cost:    inv.parts_cost    || inv.Lineitem_2_UnitPrice || 0,
    total_amount:  inv.total_amount  || inv['Total Invoice Amount'] || 0,
    oos_tier1:     inv.oos_tier1     || inv['OOS Tier 1 Category'] || '',
    oos_tier2:     inv.oos_tier2     || inv['OOS Tier 2 Category'] || '',
    comment:       inv.comment       || inv.InvoiceComment || '',
    current_decision: inv.current_decision || inv['Bill Customer'] || 'UNKNOWN'
  };
});

return normalised.map(item => ({ json: item }));

