// ── Parse LLM response and merge with invoice data ───────────────
const invoice = $('Normalise Invoice Fields').item.json;
const rawResponse = $input.first().json.message?.content || 
                    $input.first().json.choices?.[0]?.message?.content || '';

let aiResult = {};
try {
  // Strip any markdown fences if present
  const clean = rawResponse.replace(/```json|```/g, '').trim();
  aiResult = JSON.parse(clean);
} catch(e) {
  aiResult = {
    decision: 'UNCLEAR',
    confidence: 'LOW',
    reason: 'Could not parse AI response: ' + rawResponse.substring(0, 100),
    key_signal: 'PARSE_ERROR',
    flag_for_review: true
  };
}

// Determine if AI agrees with current human decision
const humanDecision = invoice.current_decision?.toUpperCase();
const aiDecision = aiResult.decision?.toUpperCase();
const agrees = humanDecision === 'UNKNOWN' ? null : (humanDecision === aiDecision);

// Financial impact of disagreement
const amount = parseFloat(invoice.total_amount) || 0;
let financialImpact = 0;
let impactType = '';

if (agrees === false) {
  financialImpact = amount;
  if (humanDecision === 'YES' && aiDecision === 'NO') {
    impactType = 'OVER_BILLING';
  } else if (humanDecision === 'NO' && aiDecision === 'YES') {
    impactType = 'UNDER_BILLING';
  }
}

return [{
  json: {
    // Original invoice
    invoice_id:      invoice.invoice_id,
    serial_number:   invoice.serial_number,
    safe_age_yr:     invoice.safe_age_yr,
    total_amount:    amount,
    oos_tier1:       invoice.oos_tier1,
    oos_tier2:       invoice.oos_tier2,
    human_decision:  humanDecision,
    // AI result
    ai_decision:     aiDecision,
    ai_confidence:   aiResult.confidence,
    ai_reason:       aiResult.reason,
    ai_key_signal:   aiResult.key_signal,
    flag_for_review: aiResult.flag_for_review || false,
    // Agreement analysis
    agrees:          agrees,
    impact_type:     impactType,
    financial_impact: financialImpact,
    // Metadata
    processed_at:    new Date().toISOString()
  }
}];

